  {"subject': 'Physics', 'year': 2024, 'question': \"A rocket propels itself by ejecting gas backwards. This is based on:\", 'options': [\"Newton's third law\", \"Newton's second law\", \"Conservation of energy\", \"Law of gravitation\"], 'correctIndex': 0, 'explanation": "Action-reaction (third law)."},
  {"subject': 'Physics', 'year': 2025, 'question': \"A 0.2 kg ball is thrown against a wall and rebounds with the same speed. If the speed is 10 m/s, what is the change in momentum?\", 'options': ['4 kg·m/s', '2 kg·m/s', '0.4 kg·m/s', '20 kg·m/s'], 'correctIndex': 0, 'explanation": "Δp = m(v - u) = 0.2(-10 - 10) = 0.2(-20) = -4 (magnitude 4)."},
  {"subject': 'Physics', 'year': 2026, 'question': \"A force of 8 N acts on a 2 kg mass for 4 s. What is the impulse?\", 'options': ['32 Ns', '16 Ns', '8 Ns', '4 Ns'], 'correctIndex': 0, 'explanation": "Impulse = F×t = 8×4 = 32 Ns."},

  // --- 81–100: Circular Motion, Gravitation ---
  {"subject': 'Physics', 'year': 2000, 'question': \"A satellite orbits Earth at constant speed. What is the direction of its acceleration?\", 'options': ['Towards the centre of Earth', 'In the direction of motion', 'Away from Earth', 'Zero'], 'correctIndex': 0, 'explanation": "Centripetal acceleration is always towards the centre."},
  {"subject': 'Physics', 'year': 2001, 'question': \"What provides the centripetal force for a car going round a flat circular track?\", 'options': ['Friction between tyres and road', 'Engine power', 'Normal reaction', 'Gravity'], 'correctIndex': 0, 'explanation": "Static friction provides the centripetal force."},
  {"subject': 'Physics', 'year': 2002, 'question': \"If a planet's distance from the sun is doubled, what happens to the gravitational force? (F ∝ 1/r²)\", 'options': ['Becomes one quarter', 'Becomes half', 'Becomes double', 'Becomes four times'], 'correctIndex': 0, 'explanation": "F ∝ 1/r² → r doubles → F becomes 1/4."},
  {"subject': 'Physics', 'year': 2003, 'question': \"The acceleration due to gravity on the surface of Earth is approximately:\", 'options': ['9.8 m/s²', '8.9 m/s²', '10.8 m/s²', '7.8 m/s²'], 'correctIndex': 0, 'explanation": "Standard value g ≈ 9.8 m/s²."},
  {"subject': 'Physics', 'year': 2004, 'question': \"If the mass of a planet is doubled and its radius is doubled, the acceleration due to gravity on its surface becomes:\", 'options': ['Half', 'Same', 'Double', 'Quarter'], 'correctIndex': 0, 'explanation": "g ∝ M/R² → (2M)/(2R)² = 2M/4R² = (1/2)(M/R²) → half."},
  {"subject': 'Physics', 'year': 2005, 'question': \"A body weighs 60 N on Earth. What would it weigh on a planet with twice the mass and half the radius of Earth?\", 'options': ['480 N', '240 N', '60 N', '120 N'], 'correctIndex': 0, 'explanation": "Weight ∝ M/R² → (2M)/(R/2)² = 2M/(R²/4) = 8(M/R²) → 8×60 = 480 N."},
  {"subject': 'Physics', 'year': 2006, 'question': \"The force that keeps the Moon in orbit around Earth is:\", 'options': ['Gravitational force', 'Centrifugal force', 'Electrostatic force', 'Nuclear force'], 'correctIndex': 0, 'explanation": "Gravity provides the centripetal force."},
  {"subject': 'Physics', 'year': 2007, 'question': \"If the radius of a circular path is doubled and the speed is constant, the centripetal force becomes:\", 'options': ['Half', 'Double', 'Quarter', 'Four times'], 'correctIndex': 0, 'explanation": "F = mv²/r → r doubled → F halved."},
  {"subject': 'Physics', 'year': 2008, 'question': \"A car of mass 1000 kg rounds a curve of radius 100 m at 20 m/s. What is the centripetal force?\", 'options': ['4000 N', '2000 N', '8000 N', '400 N'], 'correctIndex': 0, 'explanation": "F = mv²/r = 1000×400/100 = 4000 N."},
  {"subject': 'Physics', 'year': 2009, 'question': \"The universal gravitational constant G has SI unit:\", 'options': ['N·m²/kg²', 'N·kg²/m²', 'm³/kg·s²', 'Both A and C'], 'correctIndex': 3, 'explanation": "G = Fr²/(m1m2) → N·m²/kg² = (kg·m/s²)(m²)/kg² = m³/(kg·s²)."},
  {"subject': 'Physics', 'year': 2010, 'question': \"The weight of an object is maximum at:\", 'options': ['Poles', 'Equator', 'Centre of Earth', 'Top of mountain'], 'correctIndex': 0, 'explanation": "Weight is higher at poles because radius is smaller and rotation effects are absent."},
  {"subject': 'Physics', 'year': 2011, 'question': \"Which of the following is NOT a fundamental force?\", 'options': ['Friction', 'Gravity', 'Electromagnetic', 'Nuclear'], 'correctIndex': 0, 'explanation": "Friction is a derived force from electromagnetic interactions."},
  {"subject': 'Physics', 'year': 2012, 'question': \"A satellite in a circular orbit at height 2R above Earth's surface. If R is Earth's radius, the orbital speed is (g on surface = 10):\", 'options': ['√(10R/3)', '√(10R)', '√(20R)', '√(5R)'], 'correctIndex': 0, 'explanation": "v = √(GM/r) = √(gR²/(R+2R)) = √(gR/3)."},
  {"subject': 'Physics', 'year': 2013, 'question': \"The period of a satellite in a circular orbit depends on:\", 'options': ['Radius of orbit only', 'Mass of satellite only', 'Both radius and satellite mass', 'Radius and mass of Earth'], 'correctIndex': 3, 'explanation': \"T² ∝ r³/M_Earth (Kepler"s law), independent of satellite mass."},
  {"subject': 'Physics', 'year': 2014, 'question': \"A stone of mass 0.5 kg is tied to a string and whirled in a vertical circle of radius 1 m. At the top, if the tension is 0 N, what is the speed? (g=10)\", 'options': ['√10 ≈ 3.16 m/s', '√5 ≈ 2.24 m/s', '√20 ≈ 4.47 m/s', '√15 ≈ 3.87 m/s'], 'correctIndex': 0, 'explanation": "At top, tension + mg = mv²/r → 0 + 0.5×10 = 0.5×v²/1 → v² = 10 → v=√10."},
  {"subject': 'Physics', 'year': 2015, 'question': \"The gravitational force between two masses is F. If both masses are doubled and distance is halved, the new force is:\", 'options': ['16F', '8F', '4F', '2F'], 'correctIndex': 0, 'explanation": "F_new = G(2m1)(2m2)/(r/2)² = 4Gm1m2/(r²/4) = 16F."},
  {"subject': 'Physics', 'year': 2016, 'question': \"A body weighs 90 N on the surface of Earth. What is its weight at a height equal to Earth's radius?\", 'options': ['22.5 N', '45 N', '90 N', '10 N'], 'correctIndex': 0, 'explanation": "W ∝ 1/(R+h)² = 1/(2R)² = 1/4R² → 90/4 = 22.5 N."},
  {"subject': 'Physics', 'year': 2017, 'question': \"The escape velocity from Earth is about:\", 'options': ['11.2 km/s', '7.9 km/s', '3.0 km/s', '16.7 km/s'], 'correctIndex': 0, 'explanation": "Escape velocity ≈ 11.2 km/s for Earth."},
  {"subject': 'Physics', 'year': 2018, 'question': \"A planet has mass M and radius R. The acceleration due to gravity on its surface is proportional to:\", 'options': ['M/R²', 'MR²', 'M/R', 'MR'], 'correctIndex': 0, 'explanation": "g = GM/R²."},
  {"subject': 'Physics', 'year': 2019, 'question': \"A car goes over a hump-backed bridge. At the highest point, the normal reaction is:\", 'options': ['Less than mg', 'Greater than mg', 'Equal to mg', 'Zero'], 'correctIndex': 0, 'explanation": "At top, mg - N = mv²/r → N = mg - mv²/r < mg."},

