  {"subject': 'Physics', 'year': 2000, 'question': \"Density is defined as:\", 'options': ['Mass per unit volume', 'Volume per unit mass', 'Mass per unit area', 'Weight per unit volume'], 'correctIndex': 0, 'explanation": "Density = mass/volume."},
  {"subject': 'Physics', 'year': 2001, 'question': \"A substance has density 2 g/cm³. What is its density in kg/m³?\", 'options': ['2000', '2', '200', '0.002'], 'correctIndex': 0, 'explanation": "1 g/cm³ = 1000 kg/m³, so 2 g/cm³ = 2000 kg/m³."},
  {"subject': 'Physics', 'year': 2002, 'question': \"A block of volume 0.02 m³ and mass 40 kg has density:\", 'options': ['2000 kg/m³', '800 kg/m³', '4000 kg/m³', '1000 kg/m³'], 'correctIndex': 0, 'explanation": "ρ = 40/0.02 = 2000 kg/m³."},
  {"subject': 'Physics', 'year': 2003, 'question': \"Pressure is defined as:\", 'options': ['Force per unit area', 'Force per unit volume', 'Work per unit area', 'Energy per unit area'], 'correctIndex': 0, 'explanation": "P = F/A."},
  {"subject': 'Physics', 'year': 2004, 'question': \"The SI unit of pressure is:\", 'options': ['Pascal', 'Newton', 'Joule', 'Watt'], 'correctIndex': 0, 'explanation": "Pascal = N/m²."},
  {"subject': 'Physics', 'year': 2005, 'question': \"A force of 200 N is applied on an area of 0.5 m². What is the pressure?\", 'options': ['400 Pa', '100 Pa', '200 Pa', '50 Pa'], 'correctIndex': 0, 'explanation": "P = 200/0.5 = 400 Pa."},
  {"subject': 'Physics', 'year': 2006, 'question': \"A liquid of density 1000 kg/m³ is at a depth of 5 m. What is the pressure due to the liquid? (g=10)\", 'options': ['50,000 Pa', '5,000 Pa', '500 Pa', '50 Pa'], 'correctIndex': 0, 'explanation": "P = ρgh = 1000×10×5 = 50,000 Pa."},
  {"subject': 'Physics', 'year': 2007, 'question': \"A water tank is filled to a height of 4 m. What is the pressure at the bottom? (ρ=1000, g=10)\", 'options': ['40,000 Pa', '400 Pa', '4,000 Pa', '400,000 Pa'], 'correctIndex': 0, 'explanation": "P = 1000×10×4 = 40,000 Pa."},
  {"subject': 'Physics', 'year': 2008, 'question': \"The upthrust (buoyant force) on an object immersed in a fluid is equal to:\", 'options': ['Weight of displaced fluid', 'Weight of the object', 'Volume of displaced fluid', 'Density of fluid'], 'correctIndex': 0, 'explanation': \"Archimedes" principle: upthrust = weight of fluid displaced."},
  {"subject': 'Physics', 'year': 2009, 'question': \"A solid of volume 0.001 m³ is fully immersed in water (ρ=1000). What is the upthrust? (g=10)\", 'options': ['10 N', '1 N', '100 N', '0.1 N'], 'correctIndex': 0, 'explanation": "Upthrust = ρVg = 1000×0.001×10 = 10 N."},
  {"subject': 'Physics', 'year': 2010, 'question': \"A body weighs 10 N in air and 8 N when fully immersed in water. What is the upthrust?\", 'options': ['2 N', '18 N', '10 N', '8 N'], 'correctIndex': 0, 'explanation": "Upthrust = weight in air - weight in water = 10 - 8 = 2 N."},
  {"subject': 'Physics', 'year': 2011, 'question': \"The relative density of a substance is:\", 'options': ['Density of substance / Density of water', 'Density of water / Density of substance', 'Weight in air / Weight in water', 'Volume in air / Volume in water'], 'correctIndex': 0, 'explanation": "Relative density = ρ_substance / ρ_water."},
  {"subject': 'Physics', 'year': 2012, 'question': \"A piece of metal weighs 45 N in air and 35 N in water. What is its relative density?\", 'options': ['4.5', '9', '3.5', '5'], 'correctIndex': 0, 'explanation": "R.D. = Weight in air / Upthrust = 45/(45-35) = 45/10 = 4.5."},
  {"subject': 'Physics', 'year': 2013, 'question': \"A body floats in a liquid if its density is:\", 'options': ['Less than the liquid', 'Greater than the liquid', 'Equal to liquid', 'Any density'], 'correctIndex': 0, 'explanation": "Floating occurs when object density < fluid density."},
  {"subject': 'Physics', 'year': 2014, 'question': \"Atmospheric pressure at sea level is approximately:\", 'options': ['1.01×10⁵ Pa', '1.01×10³ Pa', '1.01×10⁶ Pa', '1.01×10⁴ Pa'], 'correctIndex': 0, 'explanation": "Standard atmospheric pressure = 101,325 Pa ≈ 1.01×10⁵ Pa."},
  {"subject': 'Physics', 'year': 2015, 'question': \"A barometer measures:\", 'options': ['Atmospheric pressure', 'Gauge pressure', 'Absolute pressure', 'Liquid pressure'], 'correctIndex': 0, 'explanation": "Barometer measures atmospheric pressure."},
  {"subject': 'Physics', 'year': 2016, 'question': \"A manometer is used to measure:\", 'options': ['Pressure difference', 'Absolute pressure', 'Temperature', 'Volume'], 'correctIndex': 0, 'explanation": "Manometer measures gauge pressure (difference)."},
  {"subject': 'Physics', 'year': 2017, 'question': \"A hydraulic press works on the principle of:\", 'options': ['Pascal's law', 'Archimedes\' principle', 'Bernoulli\'s principle', 'Boyle\'s law'], 'correctIndex': 0, 'explanation': \"Pascal"s law: pressure is transmitted equally in all directions in a fluid."},
  {"subject': 'Physics', 'year': 2018, 'question': \"In a hydraulic press, if the area of the small piston is 0.01 m² and force applied is 100 N, what force is exerted on the large piston of area 0.2 m²?\", 'options': ['2000 N', '200 N', '20 N', '20000 N'], 'correctIndex': 0, 'explanation": "F₁/A₁ = F₂/A₂ → 100/0.01 = F₂/0.2 → F₂ = 100×0.2/0.01 = 2000 N."},
  {"subject': 'Physics', 'year': 2019, 'question': \"A submarine can submerge by changing its:\", 'options': ['Density', 'Volume', 'Weight', 'Shape'], 'correctIndex': 0, 'explanation": "By taking water into ballast tanks, total density increases, allowing it to sink."},
  {"subject': 'Physics', 'year': 2020, 'question': \"An iceberg floats with 90% of its volume submerged. What is the density of ice relative to water?\", 'options': ['0.9', '1.1', '0.1', '9.0'], 'correctIndex': 0, 'explanation": "Fraction submerged = ρ_ice/ρ_water = 0.9 → relative density 0.9."},
  {"subject': 'Physics', 'year': 2021, 'question': \"A balloon rises because the buoyant force is:\", 'options': ['Greater than its weight', 'Less than its weight', 'Equal to its weight', 'Zero'], 'correctIndex': 0, 'explanation": "Rise occurs when buoyant force > weight."},
  {"subject': 'Physics', 'year': 2022, 'question': \"Surface tension is defined as:\", 'options': ['Force per unit length', 'Energy per unit area', 'Both A and B', 'Force per unit area'], 'correctIndex': 2, 'explanation": "Surface tension is force/length (N/m) and also energy/area (J/m²)."},
  {"subject': 'Physics', 'year': 2023, 'question': \"Capillarity is the rise or fall of liquid in a capillary tube due to:\", 'options': ['Surface tension and adhesion', 'Viscosity', 'Gravity only', 'Pressure difference'], 'correctIndex': 0, 'explanation": "Capillarity is caused by surface tension and adhesive forces."},
  {"subject': 'Physics', 'year': 2024, 'question': \"A liquid rises to height h in a capillary tube. If the tube radius is reduced to half, the height becomes:\", 'options': ['2h', 'h/2', '4h', 'h'], 'correctIndex': 0, 'explanation": "h ∝ 1/r, so r halved → h doubled."},
  {"subject': 'Physics', 'year': 2025, 'question': \"Viscosity is a measure of:\", 'options': [\"A fluid's resistance to flow\", \"A fluid's density\", \"A fluid's temperature\", \"A fluid's pressure\"], 'correctIndex': 0, 'explanation": "Viscosity is internal friction, resistance to flow."},
  {"subject': 'Physics', 'year': 2026, 'question': \"In the SI system, viscosity is measured in:\", 'options': ['Pa·s', 'N·s/m²', 'kg/(m·s)', 'All of these'], 'correctIndex': 3, 'explanation": "All are equivalent: Pa·s = N·s/m² = kg/(m·s)."},

