  {"subject': 'Physics', 'year': 2000, 'question': \"Temperature is a measure of:\", 'options': ['Average kinetic energy of molecules', 'Total internal energy', 'Heat content', 'Pressure'], 'correctIndex': 0, 'explanation": "Temperature measures the average KE of particles."},
  {"subject': 'Physics', 'year': 2001, 'question': \"Heat is a form of:\", 'options': ['Energy', 'Matter', 'Force', 'Pressure'], 'correctIndex': 0, 'explanation": "Heat is energy transfer."},
  {"subject': 'Physics', 'year': 2002, 'question': \"The SI unit of heat is:\", 'options': ['Joule', 'Calorie', 'Watt', 'Kelvin'], 'correctIndex': 0, 'explanation": "Heat is energy, measured in Joules."},
  {"subject': 'Physics', 'year': 2003, 'question': \"Specific heat capacity is the amount of heat required to raise the temperature of:\", 'options': ['1 kg by 1°C', '1 g by 1°C', '1 kg by 1 K', 'Both A and C'], 'correctIndex': 3, 'explanation": "Specific heat capacity = heat per kg per K (or °C difference)."},
  {"subject': 'Physics', 'year': 2004, 'question': \"The specific heat capacity of water is about:\", 'options': ['4200 J/kg·K', '420 J/kg·K', '42000 J/kg·K', '4.2 J/kg·K'], 'correctIndex': 0, 'explanation": "c_water ≈ 4200 J/kg·K."},
  {"subject': 'Physics', 'year': 2005, 'question': \"How much heat is needed to raise the temperature of 2 kg of water from 20°C to 50°C? (c=4200)\", 'options': ['252,000 J', '126,000 J', '504,000 J', '84,000 J'], 'correctIndex': 0, 'explanation": "Q = mcΔT = 2×4200×30 = 252,000 J."},
  {"subject': 'Physics', 'year': 2006, 'question': \"If 2 kg of water at 80°C is mixed with 3 kg at 20°C, what is the final temperature? (Assume no heat loss)\", 'options': ['44°C', '50°C', '60°C', '40°C'], 'correctIndex': 0, 'explanation": "Heat lost = heat gained: 2×c×(80-T) = 3×c×(T-20) → 160 - 2T = 3T - 60 → 5T = 220 → T=44°C."},
  {"subject': 'Physics', 'year': 2007, 'question': \"Latent heat of fusion is the heat required to:\", 'options': ['Change solid to liquid at constant temperature', 'Change liquid to gas at constant temperature', 'Raise temperature of liquid', 'Raise temperature of solid'], 'correctIndex': 0, 'explanation": "Fusion = melting (solid → liquid)."},
  {"subject': 'Physics', 'year': 2008, 'question': \"The latent heat of vaporisation of water is about:\", 'options': ['2.26×10⁶ J/kg', '3.34×10⁵ J/kg', '4200 J/kg', '1.0×10⁵ J/kg'], 'correctIndex': 0, 'explanation": "L_v ≈ 2.26×10⁶ J/kg."},
  {"subject': 'Physics', 'year': 2009, 'question': \"How much heat is needed to melt 0.5 kg of ice at 0°C? (L_f = 3.34×10⁵ J/kg)\", 'options': ['1.67×10⁵ J', '3.34×10⁵ J', '6.68×10⁵ J', '0.5×10⁵ J'], 'correctIndex': 0, 'explanation": "Q = mL = 0.5×3.34×10⁵ = 1.67×10⁵ J."},
  {"subject': 'Physics', 'year': 2010, 'question': \"In which of the following is heat transfer by convection predominant?\", 'options': ['Liquids and gases', 'Solids', 'Vacuum', 'Metals'], 'correctIndex': 0, 'explanation": "Convection occurs in fluids (liquids and gases)."},
  {"subject': 'Physics', 'year': 2011, 'question': \"Which of the following is a good conductor of heat?\", 'options': ['Copper', 'Wood', 'Plastic', 'Air'], 'correctIndex': 0, 'explanation": "Metals are good conductors; copper is a metal."},
  {"subject': 'Physics', 'year': 2012, 'question': \"Heat transfer by radiation does NOT require a:\", 'options': ['Medium', 'Temperature difference', 'Surface', 'Time'], 'correctIndex': 0, 'explanation": "Radiation can occur through vacuum (no medium needed)."},
  {"subject': 'Physics', 'year': 2013, 'question': \"A black surface is a good:\", 'options': ['Emitter and absorber of radiation', 'Reflector of radiation', 'Conductor of heat', 'Insulator'], 'correctIndex': 0, 'explanation": "Black bodies absorb and emit radiation well."},
  {"subject': 'Physics', 'year': 2014, 'question': \"The temperature at which all molecular motion stops is:\", 'options': ['0 K', '0°C', '273 K', '-273°C'], 'correctIndex': 0, 'explanation": "Absolute zero = 0 K."},
  {"subject': 'Physics', 'year': 2015, 'question': \"Convert 100°C to Kelvin.\", 'options': ['373 K', '100 K', '273 K', '173 K'], 'correctIndex': 0, 'explanation": "K = °C + 273 = 100 + 273 = 373 K."},
  {"subject': 'Physics', 'year': 2016, 'question': \"The thermal expansion of a liquid is measured by its:\", 'options': ['Coefficient of cubical expansion', 'Coefficient of linear expansion', 'Specific heat capacity', 'Latent heat'], 'correctIndex': 0, 'explanation": "Liquids expand in volume, so cubical expansion coefficient."},
  {"subject': 'Physics', 'year': 2017, 'question': \"A bimetal strip bends when heated because:\", 'options': ['Different metals have different coefficients of expansion', 'One metal is a conductor and the other is an insulator', 'They have different melting points', 'They have different specific heats'], 'correctIndex': 0, 'explanation": "Different expansion rates cause bending."},
  {"subject': 'Physics', 'year': 2018, 'question': \"The ideal gas law is given by:\", 'options': ['PV = nRT', 'PV = mRT', 'PV = NkT', 'All of these'], 'correctIndex': 3, 'explanation": "All forms are equivalent depending on constants used."},
  {"subject': 'Physics', 'year': 2019, 'question': \"A gas at 27°C has volume V. At constant pressure, what is the volume at 127°C?\", 'options': ['(400/300)V = 4/3 V', '(300/400)V = 3/4 V', '2V', 'V/2'], 'correctIndex': 0, 'explanation": "V₁/T₁ = V₂/T₂ → V₂ = V × (400/300) = 4/3 V (using Kelvin)."},
  {"subject': 'Physics', 'year': 2020, 'question': \"The zeroth law of thermodynamics deals with:\", 'options': ['Thermal equilibrium', 'Conservation of energy', 'Entropy', 'Temperature measurement'], 'correctIndex': 0, 'explanation": "Zeroth law: if A and B are in equilibrium with C, they are in equilibrium with each other."},
  {"subject': 'Physics', 'year': 2021, 'question': \"The first law of thermodynamics is a statement of:\", 'options': ['Conservation of energy', 'Conservation of momentum', 'Conservation of charge', 'Conservation of mass'], 'correctIndex': 0, 'explanation": "First law: ΔU = Q - W (energy conservation)."},
  {"subject': 'Physics', 'year': 2022, 'question': \"A refrigerator operates by transferring heat from:\", 'options': ['Cold reservoir to hot reservoir (with work input)', 'Hot reservoir to cold reservoir', 'Cold to hot spontaneously', 'No heat transfer'], 'correctIndex': 0, 'explanation": "Refrigerator pumps heat from cold to hot using external work."},
  {"subject': 'Physics', 'year': 2023, 'question': \"The entropy of an isolated system always:\", 'options': ['Increases (or stays same)', 'Decreases', 'Remains zero', 'Oscillates'], 'correctIndex': 0, 'explanation": "Second law: total entropy never decreases."},
  {"subject': 'Physics', 'year': 2024, 'question': \"A heat engine operates between 500 K and 300 K. What is the maximum efficiency?\", 'options': ['40%', '60%', '30%', '50%'], 'correctIndex': 0, 'explanation": "Efficiency = 1 - T_c/T_h = 1 - 300/500 = 0.4 = 40%."},
  {"subject': 'Physics', 'year': 2025, 'question': \"The temperature of a gas is increased from 300 K to 600 K. If the volume is kept constant, the pressure:\", 'options': ['Doubles', 'Halves', 'Quadruples', 'Remains same'], 'correctIndex': 0, 'explanation': \"At constant volume, P ∝ T (Gay-Lussac"s law)."},
  {"subject': 'Physics', 'year': 2026, 'question': \"A gas expands adiabatically. Which of the following is true?\", 'options': ['No heat exchange', 'Temperature increases', 'Heat is added', 'Pressure remains constant'], 'correctIndex': 0, 'explanation": "Adiabatic means Q = 0 (no heat exchange)."},

