  {"subject': 'Physics', 'year': 2000, 'question': \"A wave that requires a medium to propagate is a:\", 'options': ['Mechanical wave', 'Electromagnetic wave', 'Both', 'Neither'], 'correctIndex': 0, 'explanation": "Mechanical waves need a medium (e.g. sound)."},
  {"subject': 'Physics', 'year': 2001, 'question': \"Which of the following is an electromagnetic wave?\", 'options': ['Light', 'Sound', 'Water wave', 'Seismic wave'], 'correctIndex': 0, 'explanation": "Light is an electromagnetic wave; sound is mechanical."},
  {"subject': 'Physics', 'year': 2002, 'question': \"The speed of a wave is given by:\", 'options': ['v = fλ', 'v = λ/T', 'Both', 'v = f/λ'], 'correctIndex': 2, 'explanation": "v = fλ and v = λ/T are equivalent."},
  {"subject': 'Physics', 'year': 2003, 'question': \"A wave has frequency 50 Hz and wavelength 2 m. What is its speed?\", 'options': ['100 m/s', '25 m/s', '50 m/s', '10 m/s'], 'correctIndex': 0, 'explanation": "v = 50×2 = 100 m/s."},
  {"subject': 'Physics', 'year': 2004, 'question': \"The distance between two consecutive compressions in a longitudinal wave is equal to:\", 'options': ['Wavelength', 'Amplitude', 'Period', 'Frequency'], 'correctIndex': 0, 'explanation": "One wavelength is the distance between successive compressions."},
  {"subject': 'Physics', 'year': 2005, 'question': \"A sound wave has a frequency of 1000 Hz and speed 340 m/s. What is its wavelength?\", 'options': ['0.34 m', '3.4 m', '0.034 m', '34 m'], 'correctIndex': 0, 'explanation": "λ = v/f = 340/1000 = 0.34 m."},
  {"subject': 'Physics', 'year': 2006, 'question': \"Sound cannot travel in a vacuum because:\", 'options': ['There is no medium', 'There is no air', 'The pressure is zero', 'The temperature is zero'], 'correctIndex': 0, 'explanation": "Sound requires a material medium to propagate."},
  {"subject': 'Physics', 'year': 2007, 'question': \"The pitch of a sound depends on its:\", 'options': ['Frequency', 'Amplitude', 'Wavelength', 'Speed'], 'correctIndex': 0, 'explanation": "Pitch is determined by frequency."},
  {"subject': 'Physics', 'year': 2008, 'question': \"The loudness of a sound depends on its:\", 'options': ['Amplitude', 'Frequency', 'Speed', 'Wavelength'], 'correctIndex': 0, 'explanation": "Loudness is related to amplitude (intensity)."},
  {"subject': 'Physics', 'year': 2009, 'question': \"The Doppler effect is the change in frequency due to:\", 'options': ['Relative motion between source and observer', 'Change in medium', 'Change in amplitude', 'Change in temperature'], 'correctIndex': 0, 'explanation": "Doppler effect occurs when source and observer are in relative motion."},
  {"subject': 'Physics', 'year': 2010, 'question': \"A train whistle sounds higher when approaching you because:\", 'options': ['The frequency you receive is higher', 'The source frequency increases', 'The speed of sound increases', 'The amplitude increases'], 'correctIndex': 0, 'explanation": "Approaching source compresses waves → higher observed frequency."},
  {"subject': 'Physics', 'year': 2011, 'question': \"The speed of sound in air at 0°C is approximately:\", 'options': ['330 m/s', '300 m/s', '340 m/s', '350 m/s'], 'correctIndex': 0, 'explanation": "Speed of sound in air ≈ 330 m/s at 0°C (331 m/s)."},
  {"subject': 'Physics', 'year': 2012, 'question': \"The fundamental frequency of a vibrating string is inversely proportional to:\", 'options': ['Length', 'Tension', 'Mass per unit length', 'Diameter'], 'correctIndex': 0, 'explanation": "f ∝ 1/L (for a string under tension)."},
  {"subject': 'Physics', 'year': 2013, 'question': \"A pendulum swings with a period T. If the length is quadrupled, the period becomes:\", 'options': ['2T', '4T', 'T/2', 'T/4'], 'correctIndex': 0, 'explanation": "T ∝ √L, so L quadrupled → T doubled."},
  {"subject': 'Physics', 'year': 2014, 'question': \"The beat frequency is the difference between:\", 'options': ['Two frequencies', 'Two amplitudes', 'Two speeds', 'Two wavelengths'], 'correctIndex': 0, 'explanation": "Beats = |f₁ - f₂|."},
  {"subject': 'Physics', 'year': 2015, 'question': \"If two tuning forks of frequencies 256 Hz and 260 Hz are sounded together, the beat frequency is:\", 'options': ['4 Hz', '516 Hz', '8 Hz', '2 Hz'], 'correctIndex': 0, 'explanation": "Beat = 260 - 256 = 4 Hz."},
  {"subject': 'Physics', 'year': 2016, 'question': \"The time taken for one complete vibration is called:\", 'options': ['Period', 'Frequency', 'Wavelength', 'Amplitude'], 'correctIndex': 0, 'explanation": "Period T is the time for one cycle."},
  {"subject': 'Physics', 'year': 2017, 'question': \"Which of the following waves is longitudinal?\", 'options': ['Sound', 'Light', 'Water ripples', 'Radio waves'], 'correctIndex': 0, 'explanation": "Sound is a longitudinal wave (compressions and rarefactions)."},
  {"subject': 'Physics', 'year': 2018, 'question': \"In a transverse wave, the particles of the medium vibrate:\", 'options': ['Perpendicular to wave direction', 'Parallel to wave direction', 'In circles', 'Randomly'], 'correctIndex': 0, 'explanation": "Transverse: vibration is perpendicular to propagation."},
  {"subject': 'Physics', 'year': 2019, 'question': \"A wave has amplitude 0.05 m and frequency 2 Hz. What is the maximum displacement of a particle?\", 'options': ['0.05 m', '0.1 m', '0.025 m', '0.5 m'], 'correctIndex': 0, 'explanation": "Amplitude is the maximum displacement."},
  {"subject': 'Physics', 'year': 2020, 'question': \"The speed of a wave on a string depends on:\", 'options': ['Tension and mass per unit length', 'Frequency and wavelength', 'Amplitude and period', 'Only tension'], 'correctIndex': 0, 'explanation": "v = √(T/μ), where μ is mass per unit length."},
  {"subject': 'Physics', 'year': 2021, 'question': \"A pipe closed at one end has a fundamental frequency f. If the pipe is opened at both ends, the fundamental frequency becomes:\", 'options': ['2f', 'f/2', '4f', 'f'], 'correctIndex': 0, 'explanation": "Closed pipe: f₁ = v/4L; open pipe: f₁ = v/2L = 2×(v/4L) = 2f."},
  {"subject': 'Physics', 'year': 2022, 'question': \"A sound wave has a wavelength of 0.5 m in air. What is its frequency? (v=340 m/s)\", 'options': ['680 Hz', '170 Hz', '340 Hz', '1360 Hz'], 'correctIndex': 0, 'explanation": "f = v/λ = 340/0.5 = 680 Hz."},
  {"subject': 'Physics', 'year': 2023, 'question': \"The intensity of a wave is proportional to the square of the:\", 'options': ['Amplitude', 'Frequency', 'Speed', 'Wavelength'], 'correctIndex': 0, 'explanation": "Intensity ∝ (Amplitude)²."},
  {"subject': 'Physics', 'year': 2024, 'question': \"A wave travels from a deep to a shallow region. Its speed decreases. What happens to its wavelength?\", 'options': ['Decreases', 'Increases', 'Stays same', 'Frequency changes'], 'correctIndex': 0, 'explanation": "v = fλ; frequency is constant, so if v decreases, λ decreases."},
  {"subject': 'Physics', 'year': 2025, 'question': \"Ultrasound has a frequency:\", 'options': ['Above 20,000 Hz', 'Below 20 Hz', 'Between 20 and 20,000 Hz', 'Exactly 20,000 Hz'], 'correctIndex': 0, 'explanation": "Ultrasound is > 20 kHz (20,000 Hz)."},
  {"subject': 'Physics', 'year': 2026, 'question': \"Which of the following is used in SONAR?\", 'options': ['Ultrasound', 'Light', 'Radio waves', 'Infrared'], 'correctIndex': 0, 'explanation": "SONAR uses ultrasonic waves (sound)."},

