  {"subject': 'Physics', 'year': 2000, 'question': \"The speed of light in a vacuum is approximately:\", 'options': ['3×10⁸ m/s', '3×10⁶ m/s', '3×10¹⁰ m/s', '3×10⁴ m/s'], 'correctIndex': 0, 'explanation": "c ≈ 3.0×10⁸ m/s."},
  {"subject': 'Physics', 'year': 2001, 'question': \"The law of reflection states that the angle of incidence equals the angle of reflection. These angles are measured from:\", 'options': ['The normal', 'The surface', 'The ray', 'The perpendicular to the ray'], 'correctIndex': 0, 'explanation": "Angles are measured with respect to the normal."},
  {"subject': 'Physics', 'year': 2002, 'question': \"A plane mirror forms an image that is:\", 'options': ['Virtual, upright, and same size', 'Real, inverted, and magnified', 'Virtual, inverted, and same size', 'Real, upright, and diminished'], 'correctIndex': 0, 'explanation": "Plane mirror: virtual, erect, same size, laterally inverted."},
  {"subject': 'Physics', 'year': 2003, 'question': \"The refractive index of a medium is the ratio of:\", 'options': ['Speed of light in vacuum to speed in medium', 'Speed in medium to speed in vacuum', 'Angle of refraction to angle of incidence', 'Wavelength in vacuum to wavelength in medium'], 'correctIndex': 0, 'explanation": "n = c/v."},
  {"subject': 'Physics', 'year': 2004, 'question': \"Snell's law is given by:\", 'options': ['n₁ sinθ₁ = n₂ sinθ₂', 'n₁ sinθ₂ = n₂ sinθ₁', 'sinθ₁/sinθ₂ = v₁/v₂', 'Both A and C'], 'correctIndex': 3, 'explanation': \"Snell"s law: n₁ sinθ₁ = n₂ sinθ₂, also sinθ₁/sinθ₂ = v₁/v₂."},
  {"subject': 'Physics', 'year': 2005, 'question': \"Light travels from air (n=1) into glass (n=1.5). If the angle of incidence is 30°, what is the angle of refraction? (sin30=0.5)\", 'options': ['19.47°', '48.59°', '30°', '45°'], 'correctIndex': 0, 'explanation": "1×sin30 = 1.5×sinr → 0.5 = 1.5 sinr → sinr = 0.333 → r = 19.47°."},
  {"subject': 'Physics', 'year': 2006, 'question': \"Total internal reflection occurs when light goes from:\", 'options': ['Denser to rarer medium at angle greater than critical angle', 'Rarer to denser', 'Any medium at any angle', 'Denser to rarer at any angle'], 'correctIndex': 0, 'explanation": "Total internal reflection: from denser to rarer, i > critical angle."},
  {"subject': 'Physics', 'year': 2007, 'question': \"The critical angle for glass-air is about 42°. If a ray inside glass strikes the interface at 50°, what happens?\", 'options': ['Total internal reflection', 'Refraction only', 'Partial reflection and refraction', 'The ray passes straight'], 'correctIndex': 0, 'explanation": "i=50° > critical 42°, total internal reflection."},
  {"subject': 'Physics', 'year': 2008, 'question': \"A convex lens is also known as a:\", 'options': ['Converging lens', 'Diverging lens', 'Plano-concave', 'Biconcave'], 'correctIndex': 0, 'explanation": "Convex lens converges light."},
  {"subject': 'Physics', 'year': 2009, 'question': \"A concave lens forms an image that is:\", 'options': ['Virtual, upright, and diminished', 'Real, inverted, and magnified', 'Virtual, inverted, and diminished', 'Real, upright, and same size'], 'correctIndex': 0, 'explanation": "Concave lens always forms virtual, erect, diminished image."},
  {"subject': 'Physics', 'year': 2010, 'question': \"The power of a lens is measured in:\", 'options': ['Dioptres', 'Watts', 'Joules', 'Metres'], 'correctIndex': 0, 'explanation": "Power (D) = 1/f (in metres)."},
  {"subject': 'Physics', 'year': 2011, 'question': \"A lens has focal length 0.2 m. What is its power?\", 'options': ['5 D', '20 D', '2 D', '0.2 D'], 'correctIndex': 0, 'explanation": "P = 1/f = 1/0.2 = 5 D."},
  {"subject': 'Physics', 'year': 2012, 'question': \"A convex lens of focal length 10 cm forms an image 20 cm from the lens. What is the object distance (using 1/f = 1/u + 1/v)?\", 'options': ['20 cm', '10 cm', '30 cm', '40 cm'], 'correctIndex': 0, 'explanation": "1/10 = 1/u + 1/20 → 1/u = 1/10 - 1/20 = 1/20 → u=20 cm."},
  {"subject': 'Physics', 'year': 2013, 'question': \"A real image is always:\", 'options': ['Inverted', 'Upright', 'Virtual', 'Same size'], 'correctIndex': 0, 'explanation": "Real images are formed by converging rays and are inverted."},
  {"subject': 'Physics', 'year': 2014, 'question': \"The human eye focuses by changing the:\", 'options': ['Focal length of the lens', 'Distance between lens and retina', 'Size of the pupil', 'Curvature of the cornea'], 'correctIndex': 0, 'explanation": "Accommodation: eye changes focal length by altering lens shape."},
  {"subject': 'Physics', 'year': 2015, 'question': \"A person with shortsightedness (myopia) can be corrected using:\", 'options': ['Concave lens', 'Convex lens', 'Bifocal lens', 'Cylindrical lens'], 'correctIndex': 0, 'explanation": "Myopia corrected with diverging (concave) lens."},
  {"subject': 'Physics', 'year': 2016, 'question': \"Hypermetropia (longsightedness) is corrected with:\", 'options': ['Convex lens', 'Concave lens', 'Bifocal lens', 'Prism'], 'correctIndex': 0, 'explanation": "Hypermetropia corrected with converging (convex) lens."},
  {"subject': 'Physics', 'year': 2017, 'question': \"A prism disperses white light because:\", 'options': ['Different colours have different refractive indices', 'Different colours have different speeds', 'Both', 'The prism has different thicknesses'], 'correctIndex': 2, 'explanation": "Dispersion occurs because n varies with colour (wavelength), causing different speeds and angles."},
  {"subject': 'Physics', 'year': 2018, 'question': \"The colour of an object is determined by:\", 'options': ['The wavelengths it reflects', 'The wavelengths it absorbs', 'The incident light', 'Its temperature'], 'correctIndex': 0, 'explanation": "We see the reflected colour."},
  {"subject': 'Physics', 'year': 2019, 'question': \"A red filter appears red because it:\", 'options': ['Transmits red and absorbs other colours', 'Absorbs red and transmits others', 'Reflects all colours', 'Scatters blue'], 'correctIndex': 0, 'explanation": "Red filter transmits red light, absorbs others."},
  {"subject': 'Physics', 'year': 2020, 'question': \"The refractive index of water is 1.33. What is the speed of light in water? (c=3×10⁸)\", 'options': ['2.26×10⁸ m/s', '3×10⁸ m/s', '1.33×10⁸ m/s', '4×10⁸ m/s'], 'correctIndex': 0, 'explanation": "v = c/n = 3×10⁸/1.33 = 2.26×10⁸ m/s."},
  {"subject': 'Physics', 'year': 2021, 'question': \"A mirage is caused by:\", 'options': ['Total internal reflection', 'Refraction', 'Dispersion', 'Diffraction'], 'correctIndex': 0, 'explanation": "Mirage is due to total internal reflection of light in air layers of different densities."},
  {"subject': 'Physics', 'year': 2022, 'question': \"The ability of a lens to produce a magnified image is called:\", 'options': ['Magnifying power', 'Power', 'Refractive index', 'Focal length'], 'correctIndex': 0, 'explanation": "Magnifying power = angular magnification."},
  {"subject': 'Physics', 'year': 2023, 'question': \"A compound microscope has two lenses:\", 'options': ['Objective and eyepiece', 'Objective and condenser', 'Eyepiece and condenser', 'Objective and mirror'], 'correctIndex': 0, 'explanation": "Compound microscope has objective (short focal length) and eyepiece."},
  {"subject': 'Physics', 'year': 2024, 'question': \"The telescope is used to view:\", 'options': ['Distant objects', 'Nearby small objects', 'Microorganisms', 'Stars only'], 'correctIndex': 0, 'explanation": "Telescope magnifies distant objects."},
  {"subject': 'Physics', 'year': 2025, 'question': \"In a concave mirror, when the object is placed beyond the centre of curvature, the image is:\", 'options': ['Real, inverted, diminished', 'Real, inverted, magnified', 'Virtual, upright, magnified', 'Real, upright, same size'], 'correctIndex': 0, 'explanation": "Object beyond C → real, inverted, diminished (between F and C)."},
  {"subject': 'Physics', 'year': 2026, 'question': \"The focal length of a spherical mirror is half its:\", 'options': ['Radius of curvature', 'Diameter', 'Aperture', 'Object distance'], 'correctIndex': 0, 'explanation": "f = R/2."},

