  {"subject': 'Physics', 'year': 2000, 'question': \"Electric current is the flow of:\", 'options': ['Charge', 'Electrons', 'Protons', 'Both A and B'], 'correctIndex': 3, 'explanation": "Current is flow of electric charge (usually electrons)."},
