  {"subject': 'Physics', 'year': 2004, 'question': \"A resistor has a resistance of 10 Ω. A current of 2 A flows through it. What is the voltage across it?\", 'options': ['20 V', '5 V', '10 V', '0.2 V'], 'correctIndex': 0, 'explanation": "V = IR = 2×10 = 20 V."},
  {"subject': 'Physics', 'year': 2005, 'question': \"Three resistors 2 Ω, 3 Ω, and 5 Ω are connected in series. What is the total resistance?\", 'options': ['10 Ω', '1.2 Ω', '30 Ω', '3.33 Ω'], 'correctIndex': 0, 'explanation": "R_series = 2+3+5 = 10 Ω."},
  {"subject': 'Physics', 'year': 2006, 'question': \"The same resistors (2, 3, 5 Ω) are connected in parallel. What is the total resistance?\", 'options': ['0.97 Ω', '10 Ω', '30 Ω', '1.03 Ω'], 'correctIndex': 0, 'explanation": "1/R = 1/2+1/3+1/5 = 0.5+0.333+0.2=1.033 → R=0.97 Ω."},
  {"subject': 'Physics', 'year': 2007, 'question': \"Power dissipated in a resistor is given by:\", 'options': ['P = I²R', 'P = V²/R', 'P = VI', 'All of these'], 'correctIndex': 3, 'explanation": "All three are equivalent for resistors using V=IR."},
  {"subject': 'Physics', 'year': 2008, 'question': \"A 60 W bulb is connected to a 240 V supply. What is the current drawn?\", 'options': ['0.25 A', '4 A', '0.5 A', '2 A'], 'correctIndex': 0, 'explanation": "I = P/V = 60/240 = 0.25 A."},
  {"subject': 'Physics', 'year': 2009, 'question': \"A current of 3 A flows through a 10 Ω resistor for 2 minutes. How much heat is produced? (H = I²Rt)\", 'options': ['10,800 J', '3,600 J', '1,800 J', '72,000 J'], 'correctIndex': 0, 'explanation": "H = 3²×10×120 = 9×10×120 = 10,800 J."},
  {"subject': 'Physics', 'year': 2010, 'question': \"The net charge flowing through a circuit is 5 C in 2 s. What is the current?\", 'options': ['2.5 A', '10 A', '0.4 A', '5 A'], 'correctIndex': 0, 'explanation": "I = Q/t = 5/2 = 2.5 A."},
  {"subject': 'Physics', 'year': 2011, 'question': \"The resistance of a wire depends on:\", 'options': ['Length, area, resistivity', 'Only length', 'Only area', 'Only material'], 'correctIndex': 0, 'explanation": "R = ρL/A."},
  {"subject': 'Physics', 'year': 2012, 'question': \"If the length of a wire is doubled and cross-sectional area is halved, what happens to the resistance?\", 'options': ['Becomes 4 times', 'Doubles', 'Halves', 'Remains same'], 'correctIndex': 0, 'explanation": "R = ρL/A → new R = ρ(2L)/(A/2) = 4ρL/A = 4R."},
  {"subject': 'Physics', 'year': 2013, 'question': \"A battery of emf 12 V and internal resistance 1 Ω is connected to a 3 Ω resistor. What is the terminal voltage?\", 'options': ['9 V', '12 V', '3 V', '8 V'], 'correctIndex': 0, 'explanation": "I = E/(R+r) = 12/(3+1) = 3 A. Terminal V = E - Ir = 12 - 3×1 = 9 V."},
  {"subject': 'Physics', 'year': 2014, 'question': \"If the same battery is short-circuited (R=0), what is the short-circuit current?\", 'options': ['12 A', '6 A', '4 A', '1 A'], 'correctIndex': 0, 'explanation": "I = E/r = 12/1 = 12 A."},
  {"subject': 'Physics', 'year': 2015, 'question': \"A capacitor stores energy in the form of:\", 'options': ['Electric field', 'Magnetic field', 'Chemical energy', 'Thermal energy'], 'correctIndex': 0, 'explanation": "Capacitor stores energy in electric field."},
