  {"subject': 'Physics', 'year': 2017, 'question': \"A capacitor of 100 µF is charged to 12 V. What is the charge stored? (Q=CV)\", 'options': ['1.2×10⁻³ C', '1.2×10⁻⁶ C', '1.2×10⁻⁴ C', '1.2×10⁻² C'], 'correctIndex': 0, 'explanation": "Q = 100×10⁻⁶ × 12 = 1.2×10⁻³ C."},
  {"subject': 'Physics', 'year': 2018, 'question': \"Magnetic field lines always form:\", 'options': ['Closed loops', 'Straight lines', 'Open curves', 'Parallel lines'], 'correctIndex': 0, 'explanation": "Magnetic field lines are continuous closed loops."},
  {"subject': 'Physics', 'year': 2019, 'question': \"The direction of the magnetic field around a straight current-carrying conductor is given by:\", 'options': [\"Right-hand grip rule\", \"Fleming's left-hand rule\", \"Fleming's right-hand rule\", \"Lenz's law\"], 'correctIndex': 0, 'explanation": "Right-hand grip rule gives direction of magnetic field."},
  {"subject': 'Physics', 'year': 2020, 'question': \"A solenoid behaves like a:\", 'options': ['Bar magnet', 'Capacitor', 'Resistor', 'Conductor'], 'correctIndex': 0, 'explanation": "Solenoid with current produces magnetic field like a bar magnet."},
  {"subject': 'Physics', 'year': 2021, 'question': \"Electromagnetic induction was discovered by:\", 'options': ['Faraday', 'Oersted', 'Ampere', 'Ohm'], 'correctIndex': 0, 'explanation": "Faraday discovered electromagnetic induction."},
